package com.example.documentviewer;

import android.content.ContentResolver;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.view.ViewGroup;
import android.webkit.WebSettings;
import android.webkit.WebView;
import android.widget.ImageView;
import android.widget.LinearLayout;
import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;
import java.util.Locale;

public class DocumentOpenActivity extends AppCompatActivity {

    private WebView webView;
    private ImageView imageView;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        LinearLayout root = new LinearLayout(this);
        root.setLayoutParams(new LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT
        ));

        webView = new WebView(this);
        webView.setLayoutParams(new LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT
        ));
        WebSettings settings = webView.getSettings();
        settings.setAllowFileAccess(true);
        settings.setBuiltInZoomControls(true);
        settings.setDisplayZoomControls(false);

        imageView = new ImageView(this);
        imageView.setLayoutParams(new LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.MATCH_PARENT
        ));
        imageView.setAdjustViewBounds(true);
        imageView.setScaleType(ImageView.ScaleType.FIT_CENTER);

        root.addView(webView);
        root.addView(imageView);
        setContentView(root);

        handleIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleIntent(intent);
    }

    private void handleIntent(Intent intent) {
        if (intent == null || intent.getAction() == null) {
            finish();
            return;
        }

        String action = intent.getAction();
        if (!Intent.ACTION_VIEW.equals(action)) {
            finish();
            return;
        }

        Uri fileUri = intent.getData();
        if (fileUri == null) {
            finish();
            return;
        }

        String mimeType = resolveMimeType(fileUri);
        if (mimeType == null) {
            mimeType = "";
        }

        if (mimeType.startsWith("image/")) {
            showImage(fileUri);
        } else if ("application/pdf".equals(mimeType) || isPdf(fileUri)) {
            showPdf(fileUri);
        } else {
            finish();
        }
    }

    private String resolveMimeType(Uri uri) {
        String mime = getIntent().getType();
        if (mime != null && !mime.isEmpty()) {
            return mime;
        }
        ContentResolver resolver = getContentResolver();
        mime = resolver.getType(uri);
        if (mime != null && !mime.isEmpty()) {
            return mime;
        }
        String path = uri.toString().toLowerCase(Locale.US);
        if (path.endsWith(".pdf")) {
            return "application/pdf";
        }
        if (path.endsWith(".png")) {
            return "image/png";
        }
        if (path.endsWith(".jpg") || path.endsWith(".jpeg")) {
            return "image/jpeg";
        }
        if (path.endsWith(".gif")) {
            return "image/gif";
        }
        if (path.endsWith(".webp")) {
            return "image/webp";
        }
        if (path.endsWith(".bmp")) {
            return "image/bmp";
        }
        return null;
    }

    private boolean isPdf(Uri uri) {
        return uri.toString().toLowerCase(Locale.US).endsWith(".pdf");
    }

    private void showImage(Uri uri) {
        webView.setVisibility(WebView.GONE);
        imageView.setVisibility(ImageView.VISIBLE);
        imageView.setImageURI(uri);
    }

    private void showPdf(Uri uri) {
        imageView.setVisibility(ImageView.GONE);
        webView.setVisibility(WebView.VISIBLE);
        webView.loadUrl("https://drive.google.com/viewerng/viewer?embedded=true&url=" + Uri.encode(uri.toString()));
    }
}

